import { Map } from 'immutable';

function solve(nums, queries) {
    // Precompute popcount-depth for each number in nums
    const depthMap = new Map();
    for (let num of nums) {
        depthMap.set(num, getPopcountDepth(num));
    }

    // Build a segment tree for efficient range queries
    const segmentTree = new SegmentTree(depthMap);

    const answer = [];

    for (let query of queries) {
        if (query[0] === 1) {
            // Type 1 query: count numbers with depth k in [l, r]
            const l = query[1];
            const r = query[2];
            const k = query[3];
            const count = segmentTree.queryRange(l, r, k);
            answer.push(count);
        } else {
            // Type 2 query: update nums[idx] to val
            const idx = query[1];
            const val = query[2];
            nums[idx] = val;
            segmentTree.update(idx, getPopcountDepth(val));
        }
    }

    return answer;
}

