class SegmentTree {
    constructor(data) {
        this.n = data.size;
        this.tree = new Array(4 * this.n).fill(0);
        this.build(0, 0, this.n - 1, data);
    }

    build(node, l, r, data) {
        if (l === r) {
            this.tree[node] = data.get(l);
            return;
        }
        const mid = (l + r) >> 1;
        this.build(2 * node + 1, l, mid, data);
        this.build(2 * node + 2, mid + 1, r, data);
        this.tree[node] = this.tree[2 * node + 1] + this.tree[2 * node + 2];
