            const count = segmentTree.queryRange(l, r, k);
            answer.push(count);
        } else {
            // Type 2 query: update nums[idx] to val
            const idx = query[1];
            const val = query[2];
            nums[idx] = val;
            segmentTree.update(idx, getPopcountDepth(val));
        }
    }

    return answer;
}

// Function to compute popcount-depth of a number
function getPopcountDepth(x) {
    let depth = 0;
    while (x > 0) {
        x = popcount(x);
        depth++;
    }
    return depth;
}

// Function to compute popcount (number of 1s in binary representation)
function popcount(x) {
    let count = 0;
    while (x) {
        x &= x - 1;
        count++;
    }
    return count;
}

// Segment Tree implementation for range queries and point updates
class SegmentTree {
    constructor(data) {
        this.n = data.size;
        this.tree = new Array(4 * this.n).fill(0);
        this.build(0, 0, this.n - 1, data);
    }

    build(node, l, r, data) {
        if (l === r) {
            this.tree[node] = data.get(l);
            return;
        }
        const mid = (l + r) >> 1;
        this.build(2 * node + 1, l, mid, data);
        this.build(2 * node + 2, mid + 1, r, data);
        this.tree[node] = this.tree[2 * node + 1] + this.tree[2 * node + 2];
    }

    update(pos, value) {
        this._update(0, 0, this.n - 1, pos, value);
    }

    _update(node, l, r, pos, value) {
        if (l === r) {
            this.tree[node] = value;
            return;
        }
        const mid = (l + r) >> 1;
        if (pos <= mid) {
            this._update(2 * node + 1, l, mid, pos, value);
        } else {
            this._update(2 * node + 2, mid + 1, r, pos, value);
        }
        this.tree[node] = this.tree[2 * node + 1] + this.tree[2 * node + 2];
    }

    queryRange(l, r, k) {
        return this._query(0, 0, this.n - 1, l, r, k);
    }

    _query(node, nodeL, nodeR, l, r, k) {
        if (nodeR < l || nodeL > r) {
            return 0;
        }
        if (l <= nodeL && nodeR <= r) {
            return this.tree[node];
        }
        const mid = (nodeL + nodeR) >> 1;
        return this._query(2 * node + 1, nodeL, mid, l, r, k) + this._query(2 * node + 2, mid + 1, nodeR, l, r, k);
    }
}
